<?php

declare(strict_types=1);
namespace App\Http\Controllers\StudentAffairs;
use App\Http\Controllers\Controller; use App\Http\Requests\StudentAffairs\EnrollmentRequest; use App\Models\AcademicYear; use App\Models\Classroom; use App\Models\Student; use App\Models\StudentEnrollment; use App\Services\StudentAffairs\EnrollmentService; use Illuminate\Http\Request; use Illuminate\View\View;
class EnrollmentController extends Controller { public function index(Request $request): View { $enrollments=StudentEnrollment::with(['student','academicYear','classroom'])->when($request->academic_year_id,fn($q,$v)=>$q->where('academic_year_id',$v))->when($request->classroom_id,fn($q,$v)=>$q->where('classroom_id',$v))->latest()->paginate(20)->withQueryString(); return view('student-affairs.enrollments.index',['enrollments'=>$enrollments,'academicYears'=>AcademicYear::all(),'classrooms'=>Classroom::with('academicYear')->get(),'students'=>Student::where('is_active',true)->get()]); } public function store(EnrollmentRequest $request, EnrollmentService $service) { $service->enroll($request->validated()); return back()->with('status','Penempatan siswa berhasil disimpan.'); } public function transfer(Request $request, StudentEnrollment $enrollment, EnrollmentService $service) { $data=$request->validate(['classroom_id'=>['required','exists:classrooms,id'],'notes'=>['nullable','string']]); $service->transfer($enrollment,(int)$data['classroom_id'],$data['notes']??null); return back()->with('status','Pemindahan kelas berhasil disimpan sebagai histori.'); } public function destroy(StudentEnrollment $enrollment) { $enrollment->update(['enrollment_status'=>'withdrawn','completed_at'=>now()->toDateString()]); return back()->with('status','Siswa dikeluarkan dari kelas aktif.'); } }
